#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


float z = q30;
float d = q31;
float pi = q28;
float pi2inv = q29;
float mask_apex = q32;
float zoom = q27;

vec2 c = zoom*(vUvOriginal-0.5)*uAspect.xy;

float camera_apex = atan( length(c),z);

bool mask = mask_apex >= camera_apex;

float longitude = atan(c.x,c.y);
float latitude = (pi - camera_apex + asin(d*sin(camera_apex)));

vec2 polar = vec2(longitude,latitude);

vec3 p = vec3( sin(polar.x)*sin(polar.y),cos(polar.x)*sin(polar.y),cos(polar.y));

factorA = p.zx;
factorB = vec2(q22,q23);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zx = product.xy;

factorA = p.zy;
factorB = vec2(q20,q21);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zy = product.xy;

polar = vec2(atan(p.z,p.x),atan(p.y,length(p.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);


ret = mask*tex2d(sampler_pano_earth,polar);
ret = mix(ret,1,mask*tex2d(sampler_pano_earth_clouds,polar));


/*** Flexis cleaned up Moebius spiral code ***/

float cutoff = 1;
int n = -2;
float s = 0.666;

   c = (vUvOriginal-0.5)*2*uAspect.wz;
   numerator = (c + vec2(q11,q12))*64;
   denominator = c + vec2(q13,q14);
   fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,
                      numerator.y*denominator.x - numerator.x*denominator.y)/
                      (denominator.x*denominator.x + denominator.y*denominator.y);
   c = fraction-0.5;
   float1 ang_hq = n*atan(c.x,c.y);
   vec2 spiral = vec2(ang_hq*q15+q16,s*uAspect.w*log(length(c))+q17);
   spiral = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 ))*cutoff; // mirror

/**********************************************/


ret = mix(ret,GetPixel(spiral)-0.02,1-mask);
vec4 noise2 = texture3D(sampler_noisevol_hq,
                      ((vUvOriginal.xyy
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*0.4
                     );
ret -= (noise2)*.3;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


ret = 3*GetBlur3(vUv);

vec2 uv2 = vUv;

vUv *= (0.875-.06*cos(2*(ret.xx+ret.yy)));
vUv += .03*cos(2*(ret.xx+ret.yy))+.075;

   d = uTexSize.zw*4;
   d_uv = vUv;
   dx = GetBlur1(d_uv + vec2(1,0)*d) - GetBlur1(d_uv - vec2(1,0)*d);
   dy = GetBlur1(d_uv + vec2(0,1)*d) - GetBlur1(d_uv - vec2(0,1)*d);
   d_uv += vec2(dx.x,dy.x)*0.03;

ret = mix(GetBlur2(d_uv),GetPixel(d_uv),0.4);
ret = (ret.y-ret.x*0.5)*mix(vec3(1.5,0.6,0),1,ret.x)*1.4;

ret = mix(ret,0,GetBlur1(d_uv-vec2(1,1)*uTexSize.zw*32).z*0.6);
ret = mix(ret,2,GetPixel(uv2).z*0.36);
ret *= 1.4;
//ret = GetPixel(vUv);

  fragColor = ret;
}
